# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int currency = 0;
    public int damagePerHit = 10;
    
    public void TakeDamage(int damage)
    {
        health -= damage;
        if (health < 0) health = 0;
        Debug.Log("Player Health: " + health);
    }

    public void AddCurrency(int amount)
    {
        currency += amount;
        Debug.Log("Player Currency: " + currency);
    }

    public void PurchaseItem(int itemCost, int itemDamage)
    {
        if (currency >= itemCost)
        {
            currency -= itemCost;
            damagePerHit += itemDamage;
            Debug.Log("Item purchased. New damage per hit: " + damagePerHit);
        }
        else
        {
            Debug.Log("Not enough currency to purchase.");
        }
    }
}

public class Enemy : MonoBehaviour
{
    public int enemyDamage = 10;

    private PlayerStats playerStats;

    void Start()
    {
        playerStats = FindObjectOfType<PlayerStats>();
    }

    public void DealDamage()
    {
        playerStats.TakeDamage(enemyDamage);
    }
}

public class Shop : MonoBehaviour
{
    public PlayerStats playerStats;
    
    public int healthPotionCost = 20;
    public int healthPotionHeal = 30;
    public int damageUpgradeCost = 50;
    public int damageUpgradeAmount = 5;

    void Start()
    {
        playerStats = FindObjectOfType<PlayerStats>();
    }

    public void BuyHealthPotion()
    {
        if (playerStats.currency >= healthPotionCost)
        {
            playerStats.AddCurrency(-healthPotionCost);
            playerStats.health += healthPotionHeal;
            Debug.Log("Health Potion purchased. Health: " + playerStats.health);
        }
        else
        {
            Debug.Log("Not enough currency for Health Potion.");
        }
    }

    public void BuyDamageUpgrade()
    {
        playerStats.PurchaseItem(damageUpgradeCost, damageUpgradeAmount);
    }
}